const input = $input.first().json;
const body = input.body || input;

const eventId = body.event_id || body.id;
const eventType = body.event_type;
const payload = typeof body.payload === 'string' 
  ? JSON.parse(body.payload) 
  : (body.payload || {});

if (!eventId || !eventType) {
  throw new Error(`Missing required fields: event_id=${eventId}, event_type=${eventType}`);
}

// Multi-File Support
const files = payload.files || [];
const storagePath = payload.storage_path || (files[0]?.storage_path) || null;

if (!storagePath) {
  throw new Error('No storage_path in payload or files array');
}

return {
  json: {
    event_id: eventId,
    event_type: eventType,
    payload: payload,
    storage_path: storagePath,
    all_files: files,
    file_count: files.length || 1,
    email_subject: payload.subject || '',
    email_from: payload.from_address || '',
    superchat_message_id: payload.superchat_message_id || null,
    step_key: `pdf_parse:${eventId}`
  }
};

// Merge Event Data with PDF Binary
const eventData = $('Parse Event Data').first().json;
const pdfItem = $input.first();

return {
  json: {
    event_id: eventData.event_id,
    storage_path: eventData.storage_path,
    email_subject: eventData.email_subject,
    email_from: eventData.email_from
  },
  binary: pdfItem.binary
};

// Prepare payload for AI Fallback Sub-Workflow
const item = $input.first();
const binaryData = item.binary?.data;

if (!binaryData) {
  throw new Error('No binary data (PDF) available');
}

// Get actual binary buffer (filesystem-v2 fix)
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64Data = buffer.toString('base64');

const prompt = `AUFGABE: Extrahiere EXAKT die Daten aus diesem Dokument. ERFINDE NICHTS.

Extrahiere diese Felder:

1. company: Welche Wohnungsbaugesellschaft? (Suche nach "Firma" im Dokument)
   - Wenn "SAGA" oder "SAGA Unternehmensgruppe" vorkommt → "SAGA"
   - Wenn "WBS" oder "Wohnwirtschaftliche Baubetreuungs" vorkommt → "WBS"
   - Wenn "GWG" vorkommt → "GWG"
   - Wenn "Vonovia" vorkommt → "VONOVIA"
   - Wenn "GEWOBA" vorkommt → "GEWOBA"
   - Sonst → "UNBEKANNT"

2. address (Adresse der Baustelle, meist oben im Dokument):
   - street: Straße + Hausnummer
   - floor: Stockwerk/Lage (z.B. "3.Rechts", "1. OG links")
   - zip: PLZ (5-stellige Zahl, oft bei der Firma-Adresse NICHT die Baustelle)
   - city: Stadt (Standard: "Hamburg" wenn nicht anders angegeben)

3. external_ref: Referenznummer/Auftragsnummer (z.B. "108279", "Kunden-Nr.")

4. order_type: Dokumenttyp (z.B. "ANGEBOT", "Handwerkerauftrag")

5. deadline: Fertigstellungsdatum als YYYY-MM-DD (suche nach "Fertigstellung:"), sonst null

6. tenant_name: Mietername falls im Dokument vorhanden, sonst ""

7. raw_notes: Wichtige Zusatzinfos aus dem Dokument, sonst ""

WICHTIG:
- Lies NUR was im Dokument steht
- Erfinde KEINE Daten
- Antworte NUR mit JSON, keine Erklärungen, kein Markdown

{"company":"","address":{"street":"","floor":"","zip":"","city":""},"external_ref":"","order_type":"","deadline":null,"tenant_name":"","raw_notes":""}`;

return {
  json: {
    document_base64: base64Data,
    mime_type: binaryData.mimeType || 'application/pdf',
    prompt: prompt,
    step_key: `ai_analyze:${item.json.event_id}`
  }
};

// Parse AI Response and prepare project data
// Compatible with all 3 AI models (Claude, Gemini, GPT-4o)
const item = $input.first();
const eventData = $('Merge Event + Binary').first().json;

// Get AI response text (unified format from MX_06 sub-workflow)
let aiOutput = item.json.text || '';

// Clean JSON from markdown if present
aiOutput = aiOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let extracted;
try {
  extracted = JSON.parse(aiOutput);
} catch (e) {
  console.log('Raw AI output:', aiOutput);
  console.log('Model used:', item.json.model_used);
  throw new Error(`JSON Parse Error (model: ${item.json.model_used}): ${e.message}. Raw: ${aiOutput.substring(0, 200)}`);
}

const company = extracted.company || 'UNBEKANNT';
const addr = extracted.address || {};

// Domain mapping for client lookup - erweitert
const domainMap = {
  'SAGA': 'saga.de',
  'GWG': 'gwg.de',
  'WBS': 'wbs-service.de',
  'VONOVIA': 'vonovia.de',
  'GEWOBA': 'gewoba.de'
};

const projectName = [company, addr.street, addr.city].filter(Boolean).join(' - ');

return {
  json: {
    event_id: eventData.event_id,
    storage_path: eventData.storage_path,
    email_domain: domainMap[company] || null,
    detected_source: company,
    ai_model_used: item.json.model_used || 'unknown',
    ai_fallback_chain: item.json.fallback_chain || [],
    project_data: {
      name: projectName,
      object_street: addr.street || 'Unbekannt',
      object_zip: addr.zip || '00000',
      object_city: addr.city || 'Hamburg',
      object_floor: addr.floor || null,
      status: 'INTAKE',
      source: company,
      source_reference: extracted.external_ref || '',
      planned_end: extracted.deadline || null
    },
    parsed_data: {
      company: company,
      tenant_name: extracted.tenant_name,
      address: extracted.address,
      external_ref: extracted.external_ref,
      order_type: extracted.order_type,
      deadline: extracted.deadline,
      raw_notes: extracted.raw_notes,
      from: eventData.email_from,
      subject: eventData.email_subject
    }
  },
  binary: $('Merge Event + Binary').first().binary
};

// Prepare for PDF upload and merge project ID with binary
const prepareNode = $('Prepare Project Data').first();
const insertNode = $('Insert Project').first();
const clientNode = $('Lookup Client').first();

return {
  json: {
    event_id: prepareNode.json.event_id,
    project_id: insertNode.json.id,
    project_number: insertNode.json.project_number,
    original_storage_path: prepareNode.json.storage_path,
    parsed_data: prepareNode.json.parsed_data,
    client_is_fallback: clientNode.json.is_fallback || false,
    ai_model_used: prepareNode.json.ai_model_used,
    ai_fallback_chain: prepareNode.json.ai_fallback_chain
  },
  binary: prepareNode.binary
};

