  approval_type, status, project_id,
  requested_by, requested_at, request_data
) VALUES (
  'PROJECT_START', 'PENDING',
  '{{ $("Prepare for Upload").item.json.project_id }}'::uuid,
  'n8n_m1_02', now(),
  jsonb_build_object(
    'storage_path', 'projects/' || '{{ $("Prepare for Upload").item.json.project_id }}' || '/intake/auftrag.pdf',
    'file_name', 'auftrag.pdf',
    'mime_type', 'application/pdf'
  )
);

-- PDF_PARSED bleibt (Position Extraction läuft sofort)
INSERT INTO events (event_type, project_id, payload, source_system, source_flow)
VALUES (
  'PDF_PARSED',
  '{{ $('Prepare for Upload').item.json.project_id }}'::uuid,
  '{{ JSON.stringify({
    contractor_code: $('Prepare for Upload').item.json.parsed_data.company,
    pdf_storage_path: "projects/" + $('Prepare for Upload').item.json.project_id + "/intake/auftrag.pdf"
  }).replace(/'/g, "''") }}',
  'n8n',
  'M1_02_PDF_Parser_Vision'
)
RETURNING id, event_type::text, project_id;

-- Complete workflow step
SELECT complete_workflow_step(
  'pdf_parse:{{ $('Prepare for Upload').item.json.event_id }}',
  '{}'
);

